            )
            .await
        }
        CliCommand::ExportTests {
            targets,
            framework,
            module_path,
            output,
            max_iterations,
            timeout,
            scope,
            request_timeout,
            exec_timeout,
            build_timeout,
            memory_limit,
        } => {
            run_export_tests(
                &targets,
                &framework,
                &module_path,
                output.as_deref(),
