        // --- compute_cross_file_staleness tests ---

        #[test]
        fn staleness_all_fresh() {
            let reg = make_registry_for_graph(&[
                ("src/a.ts", "foo", vec![]),
            ]);
            let graph = CallGraph::from_registry(&reg);

