            current.set_deep("src/a.ts::new_fn", "d1".into());

            let previous = FingerprintRegistry::new();

            let plan = compute_cross_file_staleness(&current, &previous, &graph);
            assert_eq!(plan.stale, vec!["src/a.ts::new_fn"]);
