    frontend: &mut Frontend,
    function_name: &str,
    seed_inputs: Vec<Vec<serde_json::Value>>,
    user_inputs: Vec<Vec<serde_json::Value>>,
    param_infos: &[ParamInfo],
    config: &ExploreConfig,
) -> Result<ExploreResult, ExploreError> {

