            kind: ComplexKind::Date,
            repr: Box::new(ConcreteValue::Int(1704067200000)),
        };
        let json = concrete_to_json(&val);
        assert_eq!(json["__complex_type"], "date");
        assert_eq!(json["value"], 1704067200000_i64);
