        solved.insert("x".to_string(), ConcreteValue::Int(42));
        let param_names = vec!["x".to_string(), "name".to_string()];

        let result = overlay_solved_values(&base, &solved, &param_names);
        assert_eq!(result[0], serde_json::json!(42));
